      "status": "Open",
      "dependencies": [],
      "complexity": "L",
      "priority": 2,
      "files": [
        "starter/models.py",
        "starter/routes_order.py"
      ],
      "history": [],
      "retryCount": 0
    },
    {
      "id": "ATU-003",
      "title": "限流中间件",
      "description": "在 middleware.py 中实现限流功能：同一 user_id 在 10 秒内只能成功提交 1 笔订单，超频返回 429。在 routes_order.py 的 POST /orders 路由中集成限流。",
      "status": "Open",
      "dependencies": [
        "ATU-002"
      ],
      "complexity": "M",
      "priority": 3,
      "files": [
        "starter/middleware.py",
        "starter/routes_order.py"
      ],
      "history": [],
      "retryCount": 0
    }
  ],
  "events": [
    {
      "type": "note",
      "description": "Sprint 1 Planning — 选取 ATU-001, ATU-002 进入 Sprint Backlog。Sprint Goal: 完成产品管理和订单系统核心功能。",
