    },
    {
      "type": "note",
      "description": "Sprint 1 Round 1 Standup — Developer: 准备实现 ATU-001; Tester: 等待代码; Reviewer: 关注 Blueprint 注册和错误码",
      "timestamp": "2026-04-26T12:30:43.025Z"
    },
    {
      "type": "atu_start",
      "atu_id": "ATU-001",
      "description": "Sprint 1 Round 1 — 开始实现产品路由",
      "timestamp": "2026-04-26T12:30:43.027Z"
    },
    {
      "type": "atu_end",
      "atu_id": "ATU-001",
      "description": "ATU-001 完成 — 产品路由实现，6/6 测试通过，审查通过",
      "timestamp": "2026-04-26T12:33:34.318Z"
    },
    {
      "type": "note",
      "description": "Sprint 1 Round 2 Standup — Developer: 准备实现 ATU-002; Tester: 12 个订单测试待验证; Reviewer: 关注原子性和 RBAC",
      "timestamp": "2026-04-26T12:33:50.819Z"
    },
    {
      "type": "atu_start",
      "atu_id": "ATU-002",
      "description": "Sprint 1 Round 2 — 开始实现订单系统",
      "timestamp": "2026-04-26T12:33:50.823Z"
    }
  ],
  "tokenLog": []
}

